const numbersToWords=H=>{const p=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(H<0x14)return p[H];if(H<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](H/0xa)]+(H%0xa?'\x20'+p[H%0xa]:'');if(H<0x3e8){const z=Math['floor'](H/0x64),x=H%0x64;return(0x1===z?'εκατό':0x2===z?'διακόσια':0x3===z?'τριακόσια':0x4===z?'τετρακόσια':0x5===z?'πεντακόσια':0x6===z?'εξακόσια':0x7===z?'επτακόσια':0x8===z?'οκτακόσια':0x9===z?'εννιακόσια':'')+(x?'\x20'+numbersToWords(x):'');}return H<0xf4240?numbersToWords(Math['floor'](H/0x3e8))+'\x20χιλιάδες'+(H%0x3e8?'\x20'+numbersToWords(H%0x3e8):''):numbersToWords(Math['floor'](H/0xf4240))+'\x20εκατομμύρια'+(H%0xf4240?'\x20'+numbersToWords(H%0xf4240):'');},numberToText=(H,p='money')=>{const z=Math['floor'](H),x=Math['round'](0x64*(H-z));let X=numbersToWords(z),S=x>0x0?numbersToWords(x):'';switch(p){case'money':return S?X+'\x20ευρώ\x20και\x20'+S+'\x20λεπτά':X+'\x20ευρώ';case'time':return S?X+'\x20ώρες\x20και\x20'+S+'\x20λεπτά':X+'\x20ώρες';default:return S?X+'\x20και\x20'+S:''+X;}};